# resolve_session_id - Resolve a session argument to a numeric PID
#
# Args: $1 - session ID (numeric PID or named-session symlink)
# Output (stdout): resolved numeric PID, one line, no trailing whitespace
# Returns: 0 on success, 1 if argument is non-numeric and no matching
#          session/<name> symlink exists
#
# Used by every command that takes a "<PID>|<name>" argument:
#   - _session_show1, _session_remove1 (terminal functions)
#   - __session_start1, __session_stop1 (combinator functions)
#
# Helpers like this one (no underscore prefix) are *not* part of the
# combinator/terminal anchor set — they're plain shell utilities called
# from anchor functions. Cf. is_session_alive() in vpn-switch.sh which
# follows the same convention.
#
# This helper deliberately does NOT verify that .session/$pid exists.
# Callers check that separately so they can produce context-appropriate
# diagnostics ("Session not found" vs. "Stale session link").
resolve_session_id() {
  local session_id="$1"

  if echo "$session_id" | grep -q '^[0-9][0-9]*$'; then
    printf '%s\n' "$session_id"
    return 0
  fi

  local named_link="$VPN_SWITCH_BASE/session/$session_id"
  if [ ! -L "$named_link" ]; then
    return 1
  fi

  basename -- "$(readlink "$named_link")"
  return 0
}

