#@help ___session_stop0
# @internal batch sibling of 'session stop' (stops all active sessions)
#@end
___session_stop0() {
  # Zero-arity variant: emit a 'session stop <pid>' for EVERY session.
  #
  # Rationale: __session_disconnect1 (the eventual target) is idempotent
  # — it cleans up whether the session is alive or already dead. So
  # rather than pick one session (which risks leaving an active session
  # running if "latest" happens to be a dead one), we stop them all.
  # Each batch step routes through __session_stop1 → __session_disconnect1
  # which does the right thing for its own state.
  #
  # This also eliminates the racy double-check that the previous
  # combinator design had (alive-check in stop0, alive-check again in
  # stop1) and the duplication with _session_list0's iteration.
  local session_base="$VPN_SWITCH_BASE/.session"

  if [ ! -d "$session_base" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"No sessions found\""
    return
  fi

  local has_sessions=0
  for session_dir in "$session_base"/*/; do
    [ ! -d "$session_dir" ] && continue
    has_sessions=1
    local pid=$(basename -- "$session_dir")
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session stop \"$pid\""
  done

  if [ "$has_sessions" = "0" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"No sessions found\""
  fi
}

#@help __session_stop1
# @command session stop [<name>|<PID>]
# @summary Stop an active session; with no argument, stop all active sessions
# @group   sessions
# @param   name|PID  session to stop (default: all active sessions)
# @returns disconnect commands
# @example vpn-switch session stop work
# @see     session start
#@end
__session_stop1() {
  local session_id="$1"
  local resolved_pid

  # Accept either a numeric PID or a named-session symlink.
  if ! resolved_pid=$(resolve_session_id "$session_id"); then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"Named session not found: $session_id\""
    return
  fi

  # Check if session exists
  local session_dir="$VPN_SWITCH_BASE/.session/$resolved_pid"
  if [ ! -d "$session_dir" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"Stale session link $session_id: $resolved_pid\" \"Session directory removed - run vpn-switch session clean\""
    return
  fi

  # No alive-check here: __session_disconnect1 (and the underlying
  # disconnect.sh phases) are idempotent — they clean up whether the
  # VPN process is still running or already dead. The alive-check
  # belongs to display (list/show) and safety (remove/clean) contexts,
  # not to the stop routing path.
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session disconnect \"$resolved_pid\""
}

#@help _session_list0
# @command session list
# @summary Show all active and saved sessions
# @group   sessions
# @returns session table (active/stopped, referenced/unreferenced)
# @example vpn-switch session list
# @see     session refresh
# @see     session clean
#@end
_session_list0() {
  local session_base="$VPN_SWITCH_BASE/.session"
  local session_proto_dir="$VPN_SWITCH_BASE/session"

  # Header (always output)
  echo '# VPN Sessions:'
  echo '#'

  if [ ! -d "$session_base" ]; then
    echo '# ⚠ No active sessions (session directory missing)'
    return 0
  fi

  local has_sessions=0
  for session_dir in "$session_base"/*/; do
    [ -d "$session_dir" ] && has_sessions=1 && break
  done

  if [ "$has_sessions" = "0" ]; then
    echo '# - No active sessions'
    return 0
  fi

  # Build referenced PIDs list
  local referenced_pids=""
  if [ -d "$session_proto_dir" ]; then
    for link in "$session_proto_dir"/*; do
      [ ! -L "$link" ] && continue
      local target=$(readlink "$link" 2>>"$LOG_FILE" || echo "")
      if [ -n "$target" ]; then
        local target_pid=$(basename -- "$target")
        case " $referenced_pids " in
          *" $target_pid "*) ;;
          *) referenced_pids="$referenced_pids $target_pid" ;;
        esac
      fi
    done
  fi

  # Table header
  printf '# %-6s %-12s %-10s %-8s %-21s %-22s %s\n' 'PID' 'SESSION' 'PROTOCOL' 'IFACE' 'STATE' 'CONFIG' 'STARTED'
  printf '# %-6s %-12s %-10s %-8s %-21s %-22s %s\n' '---' '-------' '--------' '-----' '-----' '------' '-------'

  # Session rows
  for session_dir in "$session_base"/*/; do
    [ ! -d "$session_dir" ] && continue

    local session_pid=$(basename -- "$session_dir")
    local session_protocol=$(cat "$session_dir/protocol" 2>>"$LOG_FILE" || echo "unknown")
    local session_interface=$(cat "$session_dir/interface" 2>>"$LOG_FILE" || echo "unknown")
    local session_original=$(cat "$session_dir/original" 2>>"$LOG_FILE" || echo "unknown")
    local session_started=$(cat "$session_dir/started" 2>>"$LOG_FILE" || echo "unknown")
    local config_basename=$(basename -- "$session_original")

    # Collect session names for this PID (from session/ symlinks)
    local session_names=""
    if [ -d "$session_proto_dir" ]; then
      for link in "$session_proto_dir"/*; do
        [ ! -L "$link" ] && continue
        local link_name=$(basename "$link")

        # Skip system-generated links (latest, latest-wg0, etc.)
        case "$link_name" in
          latest|latest-*) continue ;;
        esac

        local target=$(readlink "$link" 2>>"$LOG_FILE" || echo "")
        local target_pid=$(basename -- "$target" 2>>"$LOG_FILE" || echo "")

        if [ "$target_pid" = "$session_pid" ]; then
          if [ -z "$session_names" ]; then
            session_names="$link_name"
          else
            session_names="$session_names,$link_name"
          fi
        fi
      done
    fi

    # If no names, use "-"
    [ -z "$session_names" ] && session_names="-"

    local vpn_state="stopped"
    is_session_alive "$session_dir" && vpn_state="active"

    local ref_state="unreferenced"
    case " $referenced_pids " in
      *" $session_pid "*) ref_state="referenced" ;;
    esac

    local state="${vpn_state}/${ref_state}"

    printf '# %-6s %-12s %-10s %-8s %-21s %-22s %s\n' "$session_pid" "$session_names" "$session_protocol" "$session_interface" "$state" "$config_basename" "$session_started"
  done

  # Footer
  cat <<'EOF'
#
# States: active=VPN running, stopped=VPN disconnected, referenced=has saved links, unreferenced=no links
# Tip: Use 'vpn-switch session clean' to remove unreferenced sessions
EOF
}

#@help __session_show0
