  if [ ! -d "$session_base" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"No active sessions found\""
    return
  fi

  # Find most recent session (by modification time)
  local latest_session=""
  local latest_mtime=0

  for session_dir in "$session_base"/*/; do
    [ ! -d "$session_dir" ] && continue

    # Get modification time (seconds since epoch)
    local mtime=$($CMD_STAT_MTIME "$session_dir" 2>>"$LOG_FILE" || echo 0)

    if [ "$mtime" -gt "$latest_mtime" ]; then
      latest_mtime="$mtime"
      latest_session="$session_dir"
    fi
  done

  if [ -z "$latest_session" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"No active sessions found\""
    return
  fi

  # Output vpn-switch command (combinator pattern)
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session show \"$(basename -- "$latest_session")\""
}

#@help _session_show1
# @command session show [<name>|<PID>]
