#@end
_session_show1() {
  local session_id="$1"
  local session_pid

  echo '# Session Show'
  echo '#'

  # Accept either a numeric PID or a named-session symlink, mirroring
  # __session_start1 / __session_stop1. Documented in
  # TUTORIAL_SESSIONS.md Step 7 ("vpn-switch session show work").
  if ! session_pid=$(resolve_session_id "$session_id"); then
    echo "# ✗ Error: Named session not found: $session_id"
    return 1
  fi

  local session_dir="$VPN_SWITCH_BASE/.session/$session_pid"
  local connect_script="$session_dir/connect.sh"

  if [ ! -d "$session_dir" ]; then
    # Distinguish stale named link from a bare missing PID
    if [ "$session_id" != "$session_pid" ]; then
      echo "# ✗ Error: Stale session link $session_id: $session_pid"
      echo "# Session directory removed - run vpn-switch session clean"
    else
      echo "# ✗ Error: Session not found: $session_pid"
    fi
    return 1
  fi

  if [ ! -f "$connect_script" ]; then
    echo "# ✗ Error: Connect script not found for session: $session_pid"
