  local session_protocol=$(cat "$session_dir/protocol" 2>>"$LOG_FILE" || echo "unknown")
  local session_interface=$(cat "$session_dir/interface" 2>>"$LOG_FILE" || echo "unknown")
  local session_original=$(cat "$session_dir/original" 2>>"$LOG_FILE" || echo "unknown")

  echo "# Session: $session_pid"
  echo "# Protocol: $session_protocol"
  echo "# Interface: $session_interface"
  echo "# Config: $(basename -- "$session_original")"
  echo '#'
  echo "# Connect script ($connect_script):"
  echo '#'

  # Display connect script contents (prefixed)
  sed 's/^/# /' "$connect_script"
}

#@help _session_remove1
# @command session remove <name>|<PID>
# @summary Remove a stopped session from the database
# @group   sessions
# @param   name|PID  session to remove (refuses if active)
# @returns shell commands (remove session directory and links)
# @example vpn-switch session remove 12345
# @see     session clean
#@end
_session_remove1() {
  local session_id="$1"
  local session_pid

  # Accept either a numeric PID or a named-session symlink, mirroring
  # __session_start1 / __session_stop1 / _session_show1.
  if ! session_pid=$(resolve_session_id "$session_id"); then
    generate_error "Named session not found: $session_id"
    return 0
  fi

  local session_dir="$VPN_SWITCH_BASE/.session/$session_pid"

  if [ ! -d "$session_dir" ]; then
    if [ "$session_id" != "$session_pid" ]; then
      generate_error "Stale session link $session_id: $session_pid" "Session directory removed - run vpn-switch session clean"
    else
      generate_error "Session not found: $session_pid"
    fi
    return 0
  fi

  # Check if VPN process still alive
  if is_session_alive "$session_dir"; then
    display warning "Session $session_pid appears to be active - process still running"
    display warning "You should stop the VPN first: vpn-switch stop"
    generate_error "Refusing to remove active session"
    return 0
  fi

  # Generate removal commands
  cat <<EOF
# Remove session directory
echo "Removing session: $session_pid"
$MODIFY_DIR_REMOVE "$session_dir"
echo "Session removed: $session_pid"
EOF
}

