#@help _session_connect1
# @internal connect-chain step for session resume
#@end
_session_connect1() {
  local session_pid="$1"
  local session_dir="$VPN_SWITCH_BASE/.session/$session_pid"

  # Validate session exists
  if [ ! -d "$session_dir" ]; then
    generate_error "Session directory not found: $session_dir"
    return 0
  fi

  # Check if connect.sh exists
  local connect_script="$session_dir/connect.sh"
  if [ ! -f "$connect_script" ]; then
    generate_error "Session has no cached connect script: $session_pid"
    return 0
  fi

  # Execute the cached script (directly, using exec - no fork)
  # The connect.sh has proper shebang and is executable (0700)
  # The script is self-contained with isolated environment
  cat <<EOF
# Resume session: $session_pid (via self-contained script)
exec "$connect_script"
EOF
}

#@help _session_save0
# @internal arity-0 sibling of 'session save' (saves as the default session)
#@end
_session_save0() {
  local session_proto_dir="$VPN_SWITCH_BASE/session"

  # Validate FIRST - find most recent session using 'latest' symlink
  local latest_link="$session_proto_dir/latest"
  if [ ! -L "$latest_link" ]; then
    generate_error "No recent session found - session/latest missing"
    display plain "Start a VPN session first"
    return 0
  fi

  # Resolve latest link to get PID
  local link_target=$(readlink "$latest_link")
  local latest_pid=$(basename -- "$link_target")

  # Verify session directory exists
  if [ ! -d "$VPN_SWITCH_BASE/.session/$latest_pid" ]; then
    generate_error "Stale latest link: points to non-existent session $latest_pid"
    return 0
  fi

  # NOW output commands (validation passed)
  # Create session/ directory if it doesn't exist
  if [ ! -d "$session_proto_dir" ]; then
    cat <<EOF
$MODIFY_DIR_CREATE "$session_proto_dir"
$MODIFY_FILE_PERMS 0750 "$session_proto_dir"
EOF
  fi

  local target_path="../.session/$latest_pid"
  local link_path="$session_proto_dir/default"

  # Output commands to create the default symlink
  # NOTE: Using ln -sfn instead of ln -sf because when the existing symlink
  # points to a directory (which .session/<PID> is), POSIX ln -sf will
  # create the link INSIDE that directory instead of replacing the symlink
  cat <<EOF
# Save session as: default
echo "# Saving session $latest_pid as 'default'"
$MODIFY_LINK_FORCE "$target_path" "$link_path"
echo "# Session saved: default -> $latest_pid"
EOF
}

