#@help _session_clean0
# @command session clean
# @summary Generate cleanup commands for stale/orphaned sessions
# @group   sessions
# @returns shell commands (review, then pipe to sh)
# @example vpn-switch session clean | sh
# @see     session remove
# @see     session refresh
#@end
_session_clean0() {
  local session_proto_dir="$VPN_SWITCH_BASE/session"
  local session_base="$VPN_SWITCH_BASE/.session"

  # Counters for summary (generation time)
  local stale_link_count=0
  local removed_count=0
  local kept_count=0
  local active_count=0

  echo "# Session cleanup (symlinks + stale sessions)"

  # Part 1: Scan for stale symlinks at GENERATION TIME
  if [ -d "$session_proto_dir" ]; then
    echo "#"
    echo "# Part 1: Stale symlink cleanup"

    local found_stale=0
    for link in "$session_proto_dir"/*; do
      [ ! -L "$link" ] && continue

      # Check if target exists NOW (generation time)
      if [ ! -e "$link" ]; then
        found_stale=1
        local link_name=$(basename -- "$link")
        local target=$(readlink "$link" 2>>"$LOG_FILE" || echo "unknown")
        local target_name=$(basename -- "$target")

        echo "echo '# Removing stale link: $link_name → $target_name'"
        echo "$MODIFY_LINK_REMOVE '$link'"
        stale_link_count=$((stale_link_count + 1))
      fi
    done

    if [ "$found_stale" -eq 0 ]; then
      echo "echo '# No stale symlinks found'"
    fi
  fi

  # Part 2: Scan for stale sessions at GENERATION TIME
  if [ -d "$session_base" ]; then
    echo "#"
    echo "# Part 2: Stale session cleanup"

    # Build list of referenced PIDs NOW (generation time)
    local referenced_pids=""
    if [ -d "$session_proto_dir" ]; then
      for link in "$session_proto_dir"/*; do
        [ ! -L "$link" ] && continue
        local target=$(readlink "$link" 2>>"$LOG_FILE" || echo "")
        if [ -n "$target" ]; then
          local target_pid=$(basename -- "$target")
          case " $referenced_pids " in
            *" $target_pid "*) ;;
            *) referenced_pids="$referenced_pids $target_pid" ;;
          esac
        fi
      done
    fi

    local found_sessions=0
    for session_dir in "$session_base"/*/; do
      [ ! -d "$session_dir" ] && continue
      found_sessions=1

      local pid=$(basename -- "$session_dir")

      # Check if session is still alive NOW (generation time)
      # Use is_session_alive() to prevent PID recycling false positives
      if is_session_alive "$session_dir"; then
        local vpn_pid=""
        if [ -f "$session_dir/vpn.pid" ]; then
          vpn_pid=$(cat "$session_dir/vpn.pid" 2>>"$LOG_FILE" || echo "")
        fi
        echo "echo '# Skipping active session: $pid (VPN process $vpn_pid running)'"
        active_count=$((active_count + 1))
        continue
      fi

      # Process is dead - check if referenced for resumption
      case " $referenced_pids " in
        *" $pid "*)
          # Dead but referenced - keep for resumption
          echo "echo '# Keeping session $pid (saved for resumption)'"
          kept_count=$((kept_count + 1))
          ;;
        *)
          # Dead and unreferenced - destroy interface and remove session
          local session_protocol=""
          local session_interface=""
          if [ -f "$session_dir/protocol" ]; then
            session_protocol=$(cat "$session_dir/protocol" 2>>"$LOG_FILE" || echo "")
          fi
          if [ -f "$session_dir/interface" ]; then
            session_interface=$(cat "$session_dir/interface" 2>>"$LOG_FILE" || echo "")
          fi

          # Note: session clean is a DATABASE cleanup function only
          # It does NOT destroy interfaces - that's the job of 'vpn-switch stop'
          # Stale interfaces should be cleaned manually or via stop/disconnect commands

          # Output remove command
          echo "echo '# Removing stale session: $pid (process dead, unreferenced)'"
          echo "$MODIFY_DIR_REMOVE '$session_base/$pid'"
          removed_count=$((removed_count + 1))
          ;;
      esac
    done

    if [ "$found_sessions" -eq 0 ]; then
      echo "echo '# No sessions found'"
    fi
  fi

  # Summary (computed at generation time, output as concrete echo)
  echo "#"
  echo "# Summary"
  if [ "$stale_link_count" -eq 0 ] && [ "$removed_count" -eq 0 ]; then
    echo "echo '# No cleanup needed'"
  else
    [ "$stale_link_count" -gt 0 ] && echo "echo '# Removed $stale_link_count stale symlink(s)'"
    [ "$removed_count" -gt 0 ] && echo "echo '# Removed $removed_count stale session(s)'"
  fi
  echo "echo '# Session cleanup complete'"
}

# _session_refresh0 - Reconcile interface ownership against the peers actually
# loaded on the live interface.
#
# Terminal function (outputs sh commands; interpreter override 'sh'). Repairs
# the drift where session/latest-$interface points at a session whose config is
# no longer the one loaded on the interface - e.g. a resume re-pointed ownership
# but `wg-quick up` then failed because the interface was already up with a
# different config (connect.sh appends the ownership symlink unconditionally).
# The loaded WireGuard peer set is the ground truth: this finds the session whose
# stored config matches and re-points the ownership symlink to it, so
# `session list` reports the session that is genuinely live.
#
# Conservative: acts only on positive evidence. If the loaded peer set cannot be
# read (interface up but needs root, non-WireGuard, etc.) ownership is left
# untouched and reported. Operates only on symlinks in the user-owned session/
# directory, so it needs no elevated privileges. Cf. session_peer_matches_interface()
# in vpn-switch.sh, which uses the same fingerprint to demote stale sessions in
# is_session_alive().
#@help _session_refresh0
# @command session refresh
# @summary Reconcile interface ownership with the loaded peers
# @group   sessions
# @returns shell commands (re-point / remove ownership symlinks)
# @example vpn-switch session refresh
# @see     session list
# @see     session clean
#@end
_session_refresh0() {
  local session_proto_dir="$VPN_SWITCH_BASE/session"
  local session_base="$VPN_SWITCH_BASE/.session"

  echo "# Reconcile interface ownership against loaded peers"

  if [ ! -d "$session_base" ]; then
    echo "echo '# No sessions found'"
    return 0
  fi

  # Referenced PIDs (saved via named links) - used to prefer user-saved sessions
  # when several sessions share an identical config.
  local referenced_pids=""
  if [ -d "$session_proto_dir" ]; then
    for link in "$session_proto_dir"/*; do
      [ ! -L "$link" ] && continue
      case "$(basename -- "$link")" in latest|latest-*) continue ;; esac
      local ref_target=$(readlink "$link" 2>>"$LOG_FILE" || echo "")
      [ -n "$ref_target" ] && referenced_pids="$referenced_pids $(basename -- "$ref_target")"
    done
  fi

  # Discover interfaces to reconcile: union of existing latest-* ownership links
  # and the interfaces of known WireGuard sessions.
  local interfaces=""
  if [ -d "$session_proto_dir" ]; then
    for link in "$session_proto_dir"/latest-*; do
      [ ! -L "$link" ] && continue
      local iname=$(basename -- "$link"); iname="${iname#latest-}"
      case " $interfaces " in *" $iname "*) ;; *) interfaces="$interfaces $iname" ;; esac
    done
  fi
  for session_dir in "$session_base"/*/; do
    [ ! -d "$session_dir" ] && continue
    [ "$(cat "$session_dir/protocol" 2>>"$LOG_FILE" || echo "")" = "wireguard" ] || continue
    local si=$(cat "$session_dir/interface" 2>>"$LOG_FILE" || echo "")
    [ -n "$si" ] || continue
    case " $interfaces " in *" $si "*) ;; *) interfaces="$interfaces $si" ;; esac
  done

  if [ -z "$interfaces" ]; then
    echo "echo '# No interfaces to reconcile'"
    return 0
  fi

  local changed=0
  for iface in $interfaces; do
    echo "#"
    echo "# Interface: $iface"

    local link="$session_proto_dir/latest-$iface"
    local current=""
    [ -L "$link" ] && current=$(basename -- "$(readlink "$link" 2>>"$LOG_FILE")")

    # Ground truth: peers loaded on the live interface (read-only, no root needed
    # on supported platforms).
    local loaded=""
    loaded=$($EXAMINE_VPN_WIREGUARD_INTERFACE "$iface" 2>>"$LOG_FILE" \
      | grep '^peer:' \
      | sed 's/^peer:[[:space:]]*//' \
      | sort)

    if [ -z "$loaded" ]; then
      # Distinguish "interface down" (positive evidence -> stale link) from
      # "up but unreadable" (no judgement).
      if $EXAMINE_NETWORK_INTERFACE_EXISTS "$iface" >/dev/null 2>&1; then
        echo "echo '# $iface: peers unreadable (needs root?) - ownership left unchanged'"
      elif [ -n "$current" ]; then
        echo "echo '# $iface: interface down - removing stale ownership ($current)'"
        echo "$MODIFY_LINK_REMOVE '$link'"
        changed=$((changed + 1))
      else
        echo "echo '# $iface: interface down, no ownership link'"
      fi
      continue
    fi

    # Find sessions whose stored config matches the loaded peer set. Collect as
    # "ref<TAB>started<TAB>pid" so a single sort picks the rightful owner:
    # referenced sessions first, then the most-recently started.
    local candidates=""
    for session_dir in "$session_base"/*/; do
      [ ! -d "$session_dir" ] && continue
      local pid=$(basename -- "$session_dir")
      [ "$(cat "$session_dir/interface" 2>>"$LOG_FILE" || echo "")" = "$iface" ] || continue
      local conf="$session_dir/$iface.conf"
      [ -f "$conf" ] || continue
      local stored=$(grep -i '^[[:space:]]*PublicKey' "$conf" 2>>"$LOG_FILE" \
        | sed 's/^[[:space:]]*[Pp]ublic[Kk]ey[[:space:]]*=[[:space:]]*//' \
        | sort)
      [ "$stored" = "$loaded" ] || continue

      local started=$(cat "$session_dir/started" 2>>"$LOG_FILE" || echo "")
      local ref=0
      case " $referenced_pids " in *" $pid "*) ref=1 ;; esac
      candidates="${candidates}${ref}	${started}	${pid}
"
    done

    local best=""
    if [ -n "$candidates" ]; then
      best=$(printf '%s' "$candidates" | grep -v '^$' | sort | tail -1 | cut -f3)
    fi

    if [ -z "$best" ]; then
      echo "echo '# $iface: loaded config matches no known session (external/unknown) - left unchanged'"
    elif [ "$current" = "$best" ]; then
      echo "echo '# $iface: ownership already correct ($best)'"
    else
      echo "echo '# $iface: re-pointing ownership ${current:-none} -> $best'"
      echo "$MODIFY_LINK_FORCE '../.session/$best' '$link'"
      changed=$((changed + 1))
    fi
  done

  echo "#"
  echo "# Summary"
  if [ "$changed" -eq 0 ]; then
    echo "echo '# Ownership already consistent - no changes'"
  else
    echo "echo '# Reconciled ownership for $changed interface(s)'"
  fi
  echo "echo '# Session refresh complete'"
}

#@help _session_validate0
# @internal session bookkeeping validation (sub-check of 'validate')
#@end
_session_validate0() {
  local session_proto_dir="$VPN_SWITCH_BASE/session"
  local session_base="$VPN_SWITCH_BASE/.session"
  local has_errors=0
  local has_warnings=0

  echo "# === Session Validation ==="
  echo "#"

  # Part 1: Check for stale symlinks in session/
  echo "# Checking session symlinks..."
  if [ -d "$session_proto_dir" ]; then
    for link in "$session_proto_dir"/*; do
      [ ! -L "$link" ] && continue

      if [ ! -e "$link" ]; then
        local target=$(readlink "$link" 2>>"$LOG_FILE" || echo "unknown")
        echo "# [ERROR] Stale symlink: session/$(basename -- "$link") → $(basename -- "$target")"
        has_errors=1
      fi
    done
  else
    echo "# [WARNING] Session directory not found: $session_proto_dir"
    has_warnings=1
  fi

  # Part 2: Check for unreferenced session directories
  echo "#"
  echo "# Checking session directories..."
  if [ -d "$session_base" ]; then
    # Build list of referenced PIDs
    local referenced_pids=""
    if [ -d "$session_proto_dir" ]; then
      for link in "$session_proto_dir"/*; do
        [ ! -L "$link" ] && continue
        local target=$(readlink "$link" 2>>"$LOG_FILE" || echo "")
        if [ -n "$target" ]; then
          local target_pid=$(basename -- "$target")
          case " $referenced_pids " in
            *" $target_pid "*) ;;
            *) referenced_pids="$referenced_pids $target_pid" ;;
          esac
        fi
      done
    fi

    # Check each session directory
    for session_dir in "$session_base"/*/; do
      [ ! -d "$session_dir" ] && continue
      local pid=$(basename -- "$session_dir")

      # Check if unreferenced
      case " $referenced_pids " in
        *" $pid "*)
          # Referenced - check metadata integrity
          local protocol_file="$session_dir/protocol"
          local original_file="$session_dir/original"
          local interface_file="$session_dir/interface"

          if [ ! -f "$protocol_file" ]; then
            echo "# [ERROR] Missing protocol metadata: .session/$pid/protocol"
            has_errors=1
          fi

          if [ ! -f "$original_file" ]; then
            echo "# [ERROR] Missing original config metadata: .session/$pid/original"
            has_errors=1
          fi

          if [ ! -f "$interface_file" ]; then
            echo "# [WARNING] Missing interface metadata: .session/$pid/interface"
            has_warnings=1
          fi
          ;;
        *)
          # Unreferenced session
          echo "# [WARNING] Unreferenced session: .session/$pid (no links point to it)"
          has_warnings=1
          ;;
      esac
    done
  fi

  # Summary
  echo "#"
  if [ "$has_errors" -eq 0 ] && [ "$has_warnings" -eq 0 ]; then
    echo "# ✓ Session validation passed - no issues found"
    return 0
  elif [ "$has_errors" -eq 0 ]; then
    echo "# ⚠ Session validation completed with warnings"
    echo "# Run 'vpn-switch session clean' to remove unreferenced sessions"
    return 0
  else
    echo "# ✗ Session validation failed - errors found"
    echo "# Run 'vpn-switch session clean' to fix stale symlinks and remove unreferenced sessions"
    return 1
  fi
}

#@help ___session_dump0
# @internal session portion of 'dump'
#@end
___session_dump0() {
  local session_pseudo="$VPN_SWITCH_BASE/session"

  # Check if session directory exists
  if [ ! -d "$session_pseudo" ]; then
    # No sessions to dump - return empty (valid for set-combinator)
    return 0
  fi

  echo "# Dump named sessions"

  # Iterate over all symlinks in session/ directory
  for session_link in "$session_pseudo"/*; do
    # Skip if no links found
    [ ! -L "$session_link" ] && continue

    local session_name=$(basename -- "$session_link")

    # Skip 'latest' symlink (transient system state, recreated on next start)
    [ "$session_name" = "latest" ] && continue

    # Resolve symlink to get actual session directory
    local session_dir=$(readlink -f "$session_link" 2>>"$LOG_FILE")
    [ ! -d "$session_dir" ] && continue

    # Read session metadata
    local protocol_file="$session_dir/protocol"
    [ ! -f "$protocol_file" ] && continue

    local original_file="$session_dir/original"
    [ ! -f "$original_file" ] && continue

    local protocol=$(cat "$protocol_file" 2>>"$LOG_FILE")
    local original_config=$(cat "$original_file" 2>>"$LOG_FILE")

    # Validate we have the required metadata
    [ -z "$protocol" ] && continue
    [ -z "$original_config" ] && continue

    # Read interface from session metadata
    local interface_file="$session_dir/interface"
    [ ! -f "$interface_file" ] && continue
    local interface=$(cat "$interface_file" 2>>"$LOG_FILE")
    [ -z "$interface" ] && continue

    # Output feingranular commands to recreate session structure
    # This avoids calling 'connect' which would try to start the VPN
    # Uses a unique PID placeholder that will be replaced at restore time
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session create \"\$\$\""
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session populate \"\$\$\" \"$protocol\" \"$interface\""
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" $protocol patch \"\$\$\" \"$original_config\""
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" $protocol configure \"\$\$\""
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session save $session_name"
  done
}

#@help __session_help0
# @command session help
# @summary Show session-management command help
# @group   sessions
# @returns help text
# @example vpn-switch session help
#@end
__session_help0() {
  # Backward compatibility: delegate to new pattern "help session"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" help session"
}

#@help ___session_inspect0
# @internal session portion of 'inspect'
#@end
___session_inspect0() {
  # Save current ANSI setting (at generation time)
  ansi_original="${VPN_SWITCH_DISPLAY_ANSI}"

  # Disable ANSI if currently enabled (suppress stderr)
  if [ "${VPN_SWITCH_DISPLAY_ANSI}" != "0" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" setenv VPN_SWITCH_DISPLAY_ANSI 0 2>/dev/null"
  fi

  # Output section header (consistent with other inspect functions)
  cat <<'EOF'
# Section: Session Status
EOF

  # Batch combinator - delegates to three vpn-switch commands
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session list"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session enumerate"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session describe"

  # Restore ANSI to original value if we changed it (suppress stderr)
  if [ "${ansi_original}" != "0" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" setenv VPN_SWITCH_DISPLAY_ANSI ${ansi_original} 2>/dev/null"
  fi

  # Re-enable cache if it was enabled (suppress stderr)
  if [ -n "${VPN_SWITCH_INTERPRETER_environment_cache}" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" environment cache on 2>/dev/null"
  fi
}

#@help _session_enumerate0
# @internal session enumeration helper
#@end
_session_enumerate0() {
  # Terminal function - enumerate named sessions (internal, used by inspect)
  # Generation-time pattern: discover now, output only concrete echo commands
  local session_proto_dir="$VPN_SWITCH_BASE/session"

  echo "# Named Sessions"
  echo "#"

  if [ ! -d "$session_proto_dir" ]; then
    echo "# (no session directory)"
    return 0
  fi

  local found=0
  for link in "$session_proto_dir"/*; do
    [ -L "$link" ] || continue
    found=1

    local name=$(basename -- "$link")
    local target=$($EXAMINE_LINK_TARGET "$link" 2>>"$LOG_FILE" || echo "unknown")

    echo "# $name → $target"
  done

  if [ "$found" -eq 0 ]; then
    echo "# (no named sessions)"
  fi
}

#@help _session_describe0
# @internal session description helper
#@end
_session_describe0() {
  # Terminal function - describe session scripts (internal, used by inspect)
  # Generation-time pattern: discover now, output only concrete comments
  local session_base="$VPN_SWITCH_BASE/.session"

  echo "# Session Scripts"
  echo "#"

  if [ ! -d "$session_base" ]; then
    echo "# (no session directory)"
    return 0
  fi

  local found=0
  for session_dir in "$session_base"/*/; do
    [ -d "$session_dir" ] || continue
    found=1

    local pid=$(basename -- "$session_dir")
    local protocol=$(cat "$session_dir/protocol" 2>>"$LOG_FILE" || echo "unknown")
    local interface=$(cat "$session_dir/interface" 2>>"$LOG_FILE" || echo "unknown")

    echo "#"
    echo "# Session $pid ($protocol / $interface):"
    echo "#   Connect: $session_dir/connect.sh"
    echo "#   Disconnect: $session_dir/disconnect.sh"

    if [ -f "$session_dir/connect.sh" ]; then
      local connect_lines=$(wc -l < "$session_dir/connect.sh" 2>>"$LOG_FILE" || echo "?")
      echo "#   Connect size: $connect_lines lines"
    fi

    if [ -f "$session_dir/disconnect.sh" ]; then
      local disconnect_lines=$(wc -l < "$session_dir/disconnect.sh" 2>>"$LOG_FILE" || echo "?")
      echo "#   Disconnect size: $disconnect_lines lines"
    fi
  done

  if [ "$found" -eq 0 ]; then
    echo "# (no sessions)"
  fi
}

# Note: is_session_alive() is defined in vpn-switch.sh (not here) because
# it's needed by batch combinators (___wireguard_stop0, ___openvpn_stop0)
# which run before modules are loaded.

